local effectIcons = {
    ["1"] = "set:bed_war_player_info.json image:effect_move_speed",
    ["8"] = "set:bed_war_player_info.json image:effect_jump",
    ["14"] = "set:bed_war_player_info.json image:effect-invisibility",
}

local function hideEngineWindow(name)
    local window = GUIManager:getWindowByName(name)
    if not window then
        return
    end
    window:SetXPosition({ 0, 6000 })
    window:SetVisible(false)
end

local function setTouchable(window, touchable)
    window:SetTouchable(touchable)
    local count = window:GetChildCount()
    if count == 0 then
        return
    end
    for index = 1, count do
        setTouchable(window:GetChildByIndex(index - 1), touchable)
    end
end
local function getActivePotionEffects()
    local potionMap = {}
    for _, potionId in pairs(potionIdMap) do
        local potionEffect = PlayerManager:getClientPlayer().Player:getActivePotionEffectById(potionId)
        if potionEffect then
            table.insert(potionMap, potionEffect)
        end
    end
    return potionMap
end

local UIPlayerInfo = class("GUIPlayerInfo", IGUILayout)

function UIPlayerInfo:onLoad()
    setTouchable(GUIManager:getPlayerInfo(), false)
    self:setEngineUI()
    self.llArmor = self:getChildWindow("BedWarPlayerInfo-Armor", GUIType.Layout)
    self.pbArmorValue = self:getChildWindow("BedWarPlayerInfo-Armor-Value", GUIType.ProgressBar)
    self.tvArmorText = self:getChildWindow("BedWarPlayerInfo-Armor-Text", GUIType.StaticText)

    self.llBuff = self:getChildWindow("BedWarPlayerInfo-Buff-List", GUIType.Layout)
end

