function UIPlayerInfo:onTick()
    local armor = Game:getPlayer():getTotalArmorValue()
    self.llArmor:SetVisible(armor > 0)
    self.pbArmorValue:SetProgress(armor / 20)
    self.tvArmorText:SetText(string.format("%d/%d", math.floor(armor), 20))

    self:updateEffectsUI()
end

function UIPlayerInfo:updateEffectsUI()
    local potionMap = getActivePotionEffects()
    local buffMap = BuffInfo.Buffs
    for _, window in pairs(effectUIs) do
        window:SetVisible(false)
    end
    for index, potionEffect in pairs(potionMap) do
        self:updateEffectUI(index, effectIcons[tostring(potionEffect:getPotionID())], potionEffect:getDuration() / 20)
    end

    local potionMapIndex = #potionMap
    for index, buff in pairs(buffMap) do
        local buffDuration = buff.endTime - os.time()
        if buffDuration < 0 then
            buffDuration = 0
        end
        self:updateEffectUI(index + potionMapIndex, buff.image, buffDuration)
    end

    return potionMap
end

function UIPlayerInfo:updateEffectUI(index, image, duration)
    local newWindow = function(xPosition)
        local effectIcon = GUIManager:createGUIWindow(GUIType.StaticImage, "BedWarPlayerInfo-Effect-" .. GUIManager:applyWindowId())
        effectIcon:SetWidth({ 0, 30 })
        effectIcon:SetHeight({ 0, 30 })
        effectIcon:SetXPosition({ 0, xPosition })
        self.llBuff:AddChildWindow(effectIcon)

        local effectTime = GUIManager:createGUIWindow(GUIType.StaticText, "BedWarPlayerInfo-Effect-Time-" .. GUIManager:applyWindowId())
        effectTime:SetArea({ 0, 18 }, { 0, 15 }, { 0, 0 }, { 0, 0 })
        effectTime:SetFont(GUIFontManager:Instance():GetFont("HT12"))
        effectTime:SetTextBoader(Color.BLACK)
        effectIcon:AddChildWindow(effectTime)
        table.insert(effectUIs, effectIcon)
        return effectIcon
    end
    local window = effectUIs[index]
    if not window then
        local xPosition = 38 * (index - 1)
        window = newWindow(xPosition)
    end
    window:SetImage(image)
    window:GetChildByIndex(0):SetText(math.floor(duration))
    window:SetVisible(true)
end

return UIPlayerInfo